update public.lessons l set enhancements = $ench${"industryStory":"\"Tell me about yourself\" — and the candidate launched into their entire life story, lost the thread, and never mentioned testing. The interviewer's first impression was set. A crisp, structured pitch frames the whole conversation in your favour.","badGood":{"label":"answering \"tell me about yourself\"","bad":"\"Well, I was born in... then I did lots of different jobs... and recently I got interested in computers...\"","good":"\"I'm a QA tester focused on practical, risk-based testing. Recently I built a portfolio covering test design, defects, API testing and SQL. I'm drawn to this role because you value quality early, and I'd bring an eye for detail and clear communication.\""},"davidTip":"Use Present → Past → Future, in 60–90 seconds. The interviewer decides how the rest of the conversation feels in your first minute — a calm, structured pitch buys goodwill for everything that follows.","miniChallenge":"Write your pitch using Present (who you are now) → Past (a relevant highlight) → Future (why this role). Time it under 90 seconds.","modelAnswer":"## Example\nPresent: \"I'm a detail-driven QA tester.\" Past: \"I recently completed a structured testing programme and built a full portfolio.\" Future: \"I'm excited about this role because you ship quality early, and I want to bring my test-design and communication skills to your team.\"","resourcePreview":{"name":"\"Tell Me About Yourself\" — Elevator Pitch Template","purpose":"A repeatable Present→Past→Future formula for the opener.","whenToUse":"Use it to draft and rehearse your pitch.","formats":["DOCX","PDF"]}}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'qa-interview-accelerator'
  and m.module_number = 2 and l.lesson_number = 1;

update public.lessons l set enhancements = $ench${"industryStory":"A candidate with limited paid experience undersold themselves — \"I've only done a course\". Reframed around what they had actually built (test cases, bug reports, a portfolio), the same background sounded credible and relevant.","davidTip":"Position what you have done, not what you lack. \"I built a QA portfolio with real artefacts\" lands far better than \"I'm just starting out\". Lead with evidence and relevance, and never apologise for your level.","miniChallenge":"Write two sentences positioning your experience for a junior QA role, leading with concrete things you have done.","modelAnswer":"## Example\n\"I've built a hands-on QA portfolio — a test case pack using equivalence and boundary techniques, professional bug reports, and an API testing collection. I'm now looking to apply those skills in a team and keep growing.\""}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'qa-interview-accelerator'
  and m.module_number = 2 and l.lesson_number = 2;

update public.lessons l set enhancements = $ench${"industryStory":"A career changer from customer service worried their background was irrelevant. In fact, their communication, attention to detail and user empathy were exactly what made them a strong tester — once they learned to frame those transferable skills.","visualAid":{"type":"comparison","title":"Transferable skills → QA value","headers":["From a previous role","Why it helps in QA"],"rows":[["Customer service","User empathy, clear communication"],["Admin / operations","Attention to detail, process"],["Teaching","Explaining issues clearly"],["Any role","Reliability, curiosity, ownership"]]},"davidTip":"Career changers: do not hide your past — translate it. As a hiring manager, I value a tester who brings user empathy from customer service or rigour from operations. Name the transferable skill and tie it to testing.","miniChallenge":"List three skills from your background (any field) and write how each makes you a better tester.","modelAnswer":"## Example\n\"Customer service gave me empathy for how real users get confused — useful for usability testing. Operations gave me process discipline — useful for thorough, repeatable test coverage. Both built clear communication.\"","portfolioBuilder":"A short \"why I moved into QA and what I bring\" narrative is worth preparing — career-changer stories, told well, are memorable and persuasive."}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'qa-interview-accelerator'
  and m.module_number = 2 and l.lesson_number = 3;

update public.lessons l set enhancements = $ench${"davidTip":"For this assignment, make your story specific and confident, leading with evidence. A vague, apologetic story is forgettable; a focused one with real artefacts is not.","miniChallenge":"Before submitting, record your pitch and trim anything over 90 seconds or that does not earn its place.","managersReview":{"intro":"If I heard your career story as a hiring manager, I would look for:","strengths":["A structured, concise pitch","Concrete evidence (portfolio/artefacts)","Transferable skills framed as QA value"],"gaps":["Rambling chronological life story","Apologising for experience level","No link to the role"],"improvements":["Use Present→Past→Future","Lead with what you have built","Tie your background to testing"]}}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'qa-interview-accelerator'
  and m.module_number = 2 and l.lesson_number = 4;

